    PaymentBasketSet pbs=(PaymentBasketSet) request.getAttribute("PBS");

    for(RemoteEntry emanual:rqrmanual) {
        String opportunityName = emanual.getFieldValue("1002034");

        if ("台灣富士軟片資訊股份有限公司".equals(opportunityName)) continue;//discounted price partner, no commission needed

        //find all wire records for this opportunity
        RemoteQuery rqwire = new RemoteQuery("www.ragic.com", Const.AP_TEAMRAGIC, "/sales", 15);
        rqwire.setAsSupport();
        rqwire.setEIDNaming();
        rqwire.addWhere("1002138,eq," + opportunityName);
        RemoteQueryResult rqrwire = rqwire.query();

        for (RemoteEntry eWire : rqrwire) {

            Date createDate = Encoder.parseStandardDate(eWire.getFieldValue("1002133"));
            String amountString = eWire.getFieldValue("1002134");
            double amount = Encoder.parseDouble(amountString, 0);

            PaymentBasketItem pbitem=new PaymentBasketItem(
                    "wire_"+eWire.getId(),
                    createDate,
                    0,
                    amount,
                    apname
            );
            pbitem.setCommissionPercent(0.2);
            pbs.addPaymentBasketItem(partnerEmail, pbitem);
        }
    }


